import math

def solution():
    count = 0
    for n in range(1, 101):
        for r in range(0, n + 1):
            # Use math.comb for robust integer combination calculation
            if math.comb(n, r) > 1000000:
                count += 1
    return count


if __name__ == "__main__":
    print(solution())
